uint32_t* primes = malloc(203739216 * sizeof(uint32_t));
size_t p_idx = 0;

for (size_t n=2; n<=0xFFFFFFFF; n++) {
    if ( !bitarray_get(list, n) ) {
        primes[p_idx] = (uint32_t) n;
